{{ {{{|safesubst:}}}#invoke:Unsubst||date=__DATE__ |$B=
{{Ambox
| name  = Cleanup-lang
| subst = <includeonly>{{subst:</includeonly><includeonly>substcheck}}</includeonly>
| small = {{{small|}}}
| type  = style
| image = 
| issue = This {{{1|article}}} should '''specify the language''' of its non-English content, using {{tl|langx}}, {{tl|transliteration}} for transliterated languages, and {{tl|IPA}} for phonetic transcriptions, with an appropriate [[Lists of ISO 639 codes|ISO 639 code]]. Wikipedia's [[:Category:Wikipedia multilingual support templates|multilingual support templates]] may also be used{{#if:{{{iso|}}}|&nbsp;- notably <code>{{{iso}}}</code> for {{ISO 639 name|{{{iso}}}}}.|.<includeonly>{{category handler|all=[[Category:Pages with non-English text lacking appropriate markup and no ISO hint]]|nocat={{{nocat|}}}}}</includeonly>}}
| fix = [[Template:Lang#Rationale|See why]].
| date  = {{{date|}}}
| cat   = {{category handler|all=Pages with non-English text lacking appropriate markup|nocat={{{nocat|}}}}}
}}
}}<noinclude>
{{Documentation}}
</noinclude>

